SET NAMES utf8mb4;

CREATE TABLE IF NOT EXISTS dasha_phala (
    id                  BIGINT UNSIGNED NOT NULL AUTO_INCREMENT,
    maha_lord           ENUM('Sun','Moon','Mars','Mercury','Jupiter','Venus','Saturn','Rahu','Ketu') NOT NULL,
    antar_lord          ENUM('Sun','Moon','Mars','Mercury','Jupiter','Venus','Saturn','Rahu','Ketu') NOT NULL,
    language            VARCHAR(16)     NOT NULL DEFAULT 'hi',
    positive_text       TEXT            NULL,
    negative_text       TEXT            NULL,
    remedy_text         TEXT            NULL,
    updated_by_staff_id BIGINT UNSIGNED NULL,
    updated_at          TIMESTAMP       NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
    PRIMARY KEY (id),
    UNIQUE KEY uq_dasha_phala_combo (maha_lord, antar_lord, language)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

INSERT INTO dasha_phala (maha_lord, antar_lord, language, positive_text, negative_text, remedy_text) VALUES
('Sun','Sun','hi',
 'यदि सूर्य स्वोच्च, स्वक्षेत्री, बलवान या शुभभावेश होकर 1, 4, 7, 10, 5, 9, 11 भावों में हो, तो धन-धान्य की वृद्धि होती है।',
 'यदि सूर्य नीचगत, अशुभ भाव या अशुभ राशि (अतिशत्रु, शत्रुक्षेत्री) में हो, तो धन-धान्य की हानि होती है। यदि सूर्य 2, 7 भावेश हो तो अपमृत्यु (दुर्घटना आदि) का भय होता है।',
 'मृत्युंजय मन्त्र का जप, सूर्य दान और सूर्योपासना करनी चाहिए।'),
('Sun','Moon','hi',
 'चन्द्रमा केन्द्र या त्रिकोण में हो तो विवाह, शुभ मांगलिक कार्य, धन-धान्य, मकान, पशु व वाहन की वृद्धि होती है। स्वक्षेत्री या उच्चगत हो तो स्त्रीसुख, धनलाभ, पुत्रलाभ और राजा की कृपा से मनोरथ सिद्ध होता है। महादशेश से 9, 11, 4, 7, 10 में चन्द्रमा हो या शुभयुक्त हो तो भोग, भाग्य, राज्यलाभ, वाहन व पुत्र-पौत्रादि की वृद्धि होती है।',
 'चन्द्रमा क्षीण या पापयुक्त हो तो स्त्री-पुत्रादि को कष्ट, बदनामी, विरोध और धन-पशु की हानि होती है। 6, 8, 12 में चन्द्रमा हो तो पानी से भय, मनोविकार, बन्धन, रोग व स्थानभ्रंश होता है। यदि चन्द्रमा 2, 7 भावेश हो तो अपमृत्यु का भय होता है।',
 'सफेद गाय या दुधारू भैंस का दान करना चाहिए।'),
('Sun','Mars','hi',
 'मंगल स्वोच्च, स्वक्षेत्र, एकादश या केन्द्र-त्रिकोण में हो तो शुभ कार्य, भूमि-कृषि लाभ, धन-धान्य वृद्धि और लाल वस्त्रों की प्राप्ति होती है। लग्नेश व मंगल साथ हों तो सुख व राजप्रीति मिलती है। बहुत सी सेना का स्वामित्व, शत्रु नाश, मन में उत्साह और भाइयों की बढ़ोत्तरी होती है।',
 'महादशेश से 8, 12 में मंगल हो या पापयुक्त/निर्बल हो तो क्रूर बुद्धि, मनोविकार, कारागृहवास, बन्धुओं व भाइयों से वैर और कार्यहानि होती है। मंगल नीचगत हो तो राजकोप से धनहानि तथा 2, 7 भावेश हो तो शरीर में जड़ता और मनोविकार होता है।',
 'वेदपाठ, जप, दान और साँड छोड़ना आदि शान्ति कार्य करने चाहिए।'),
('Sun','Rahu','hi',
 'केन्द्र या त्रिकोण में होने पर पहले दो मास के बाद सुख होता है। शुभ ग्रह युक्त या शुभ नवांश में हो तो अच्छा स्वास्थ्य, सन्तोष और राजा से मित्रता होती है। महादशेश से शुभ भावों (या 3, 6, 10, 11) में हो तो राजसम्मान, भाग्यवृद्धि और घर में प्रसन्नता के अवसर आते हैं।',
 'पहले दो मास तक धननाश, चोर, सर्प, घाव और स्त्री-पुत्रादि को महान भय व कष्ट होता है। 8, 12 में राहु हो या निर्बल हो तो बन्धन, कारावास, जिगर/तिल्ली/क्षय रोग व अचल सम्पत्ति की हानि होती है। 2, 7 भावेश से युक्त हो तो अपमृत्यु व सर्प का भय होता है।',
 'दुर्गापाठ, भेड़-बकरी का दान, और काली गाय या भैंस का दान करना चाहिए।'),
('Sun','Jupiter','hi',
 'केन्द्र-त्रिकोण, स्वोच्च, स्वक्षेत्री या मित्रवर्ग में हो तो विवाह, राजा से भेंट, धन-धान्य व पुत्र लाभ तथा इष्ट सिद्धि होती है। 9, 10 भावेश हो तो राज्यलाभ, प्रतिष्ठित वाहन और पद-स्थान वृद्धि होती है। शुभ भावों में हो तो भाग्य वृद्धि, दान-धर्म की योग्यता और गुरु भक्ति होती है।',
 '6, 8 भावों में या नीच/पापयुक्त हो तो स्त्री-पुत्रादि से पीड़ा, शरीर कष्ट, राजप्रकोप, पापी लोगों के कारण धनलाभ व मनोविकार होते हैं।',
 'सुवर्णदान, अपने इष्ट देवता का जप और कपिला गौ का दान करना चाहिए।'),
('Sun','Saturn','hi',
 'केन्द्र-त्रिकोण या एकादश में हो तो शत्रुओं का नाश, बहुत सुख और विवाहादि मांगलिक कार्य होते हैं। उच्चगत, स्वक्षेत्री या मित्रक्षेत्र में हो तो कल्याणकारक वस्तुओं का संग्रह, राजसम्मान और अनेक प्रकार से धनागम होता है।',
 '8, 12 में या पापयुक्त हो तो वातरोग, ज्वर, पेचिश, बन्धन, कार्यनाश और अचानक कलह होती है। नीचगत शनि हो तो माता-पिता का वियोग और अधिक भागदौड़ होती है। 2, 7 भावेश हो तो अपमृत्यु का भय होता है।',
 'काली गाय या भैंस का दान, मृत्युंजय मन्त्र का जप और भेड़ या बकरी का दान करना चाहिए।'),
('Sun','Mercury','hi',
 'स्वोच्च, स्वक्षेत्र, केन्द्र-त्रिकोण या लाभ स्थान में हो तो राज्यप्राप्ति, स्त्री-पुत्र का सुख, तीर्थाटन व पशुधन की वृद्धि होती है। 5, 9, 10 भावों में हो तो मान-सम्मान, धर्म-कर्म वृद्धि और विवाह व पुत्रोत्पत्ति होती है। शुभ भावों में हो तो अपनी प्रशस्ति में काव्यादि रचना, विशिष्ट भोजन-वस्त्र की प्राप्ति और इन्द्र तुल्य स्तर प्राप्त होता है।',
 '6, 8, 12 में या नीचगत हो तो शरीरकष्ट, मनस्ताप, परिवारजनों को पीड़ा, दशारम्भ में दुःख और अन्त में राजभय व वृथा भ्रमण होता है। 2, 7 भावेश हो तो शरीर कष्ट व ज्वरादि रोग होते हैं।',
 'विष्णुसहस्रनाम का पाठ, अन्नदान और चाँदी की विष्णुप्रतिमा का दान करना चाहिए।'),
('Sun','Ketu','hi',
 'यदि लग्नेश के साथ हो तो प्रारम्भ में सुख व धनप्राप्ति होती है। 3, 6, 10, 11 भावों में, योगकारक के साथ या शुभ वर्ग में हो तो शुभकर्मों का फल, पुत्र-स्त्री सुख, विचित्र वस्त्रों की प्राप्ति और यशोलाभ होता है।',
 'सामान्यतः शरीरकष्ट, मानसिक अशान्ति, धनव्यय, राजकोप और पारिवारिक कलह होती है। 8, 12 में और पापयुक्त हो तो गाल या दाँतों में रोग, मूत्र रोग, स्थान परिवर्तन, पिता की मृत्यु व विदेश पलायन होता है। 2, 7 भावेश के साथ हो तो अपमृत्यु का भय होता है।',
 'दुर्गा जप पाठादि और बकरे का दान करना चाहिए।'),
('Sun','Venus','hi',
 'केन्द्र-त्रिकोण, स्वोच्च, स्वक्षेत्र या शुभ वर्ग में हो तो प्रिय स्त्री समागम, राज्यलाभ, उत्साह, नित्य मधुर भोजन, मणिमुक्तादि का लाभ और प्रतिष्ठित वाहन (पालकी आदि) की प्राप्ति होती है।',
 '6, 8, 12 में या बलहीन हो तो राजकोप, मन क्लेश और पुत्र-स्त्री-धन की हानि होती है। अन्तर्दशा के अन्त में यशो हानि (बदनामी) और स्थानभ्रंश होता है। यदि शुक्र सप्तमेश हो तो शरीर कष्ट और 8, 12 भाव में हो तो अपमृत्यु का भय होता है।',
 'मृत्युंजय जप, रुद्र जप या अभिषेक और सफेद गाय या भैंस का दान करना चाहिए।'),
('Moon','Moon','hi',
 'यदि चन्द्रमा स्वोच्च या स्वक्षेत्र में हो, त्रिकोण या लाभस्थान में हो या 9, 10 भावेश से युक्त हो तो हाथी-घोड़ों का ऐश्वर्य, देवता व गुरु के प्रति भक्ति, सत्कीर्ति, राज्यलाभ और बहुत सुख प्राप्त होता है। पूर्ण चन्द्रमा होने पर सामर्थ्य में वृद्धि और सेनापतित्व मिलता है।',
 'चन्द्रमा पापयुक्त, नीच या 6, 12 भावगत हो तो तत्काल धन का नाश, पद की अवनति, शरीर में आलस्य, राजा के मन्त्री से विरोध, माता को कष्ट, मानसिक सन्ताप व बन्धुओं की हानि होती है। यदि 2, 7 भावेश हो या 8, 12 भावेश से युक्त हो तो देह में आलस्य, उत्साह भंग और अपमृत्यु का भय होता है।',
 'शान्ति के लिए सफेद गाय या दुधारू भैंस का दान करना चाहिए।'),
('Moon','Mars','hi',
 'मंगल लग्न से केन्द्र-त्रिकोण में हो तो सौभाग्य वृद्धि, राजसम्मान, वस्त्राभूषणों की प्राप्ति, भवन-गृहादि की वृद्धि, वाद-विवाद में विजय और सुख होता है। मंगल उच्चगत या स्वक्षेत्री हो तो सर्वत्र सफलता मिलती है।',
 'मंगल 8, 12 में, पापयुक्त या शत्रुदृष्ट हो तो शरीरकष्ट, घर की हानि, विवाद में पराजय, सेवकों में कलह, राजा से विरोध, बन्धुओं से वियोग और कठोर वचन बोलने का स्वभाव होता है। 2, 7 भावेश या अष्टमेश होकर अष्टम में हो तो विशेष शरीर कष्ट होता है।',
 'शान्ति के लिए विद्वान् ब्राह्मणों का सत्कार करना चाहिए।'),
('Moon','Rahu','hi',
 'दशारम्भ में कुछ शुभ फल प्राप्त होते हैं। शुभ युक्त, शुभ दृष्ट, उपचय भावों में या योग कारकों से सम्बन्धित राहु सब कार्यों में सफलता, वाहन-वस्त्र का लाभ और वाञ्छित कार्य सिद्धि देता है। नैऋत्य या पश्चिम दिशा में किसी बड़े व्यक्ति से भेंट हो सकती है। केन्द्र, त्रिकोण, 3, 11 में हो तो तीर्थयात्रा, धार्मिक कार्य और परोपकार होते हैं।',
 'दशारम्भ के बाद शत्रु, चोर, सर्प, राजा और चौपाए पशु से भय, बन्धु नाश, मित्र व मान हानि होती है। 8, 12 में या बलहीन हो तो स्थानहानि, मन में दुःख, पुत्र-स्त्री-शरीर कष्ट तथा बिच्छू-सर्पादि से भय होता है। 2, 7 भावों में शरीर कष्ट होता है।',
 'रुद्रजप तथा छाग (भेड़ या बकरा) का दान करना चाहिए।'),
('Moon','Jupiter','hi',
 'केन्द्र-त्रिकोण, लाभस्थान, स्वोच्च या स्वगृह में हो तो राज्यलाभ, प्रसन्नता का वातावरण, वस्त्रालंकार, राज-मित्रता, धनागम, गर्भाधान व मनोरथ सिद्धि होती है। दशेश से केन्द्र, त्रिकोण या 3, 11 में हो तो वाहन-पशु लाभ, भाइयों के सहयोग से लाभ, धीरता, पराक्रम वृद्धि और यज्ञादि धार्मिक कार्य होते हैं।',
 '6, 8, 12 में, नीचगत, अस्त या पापयुक्त हो तो अमंगल कार्य, गुरु-पुत्रादि का नाश, स्थान परिवर्तन, मन दुःख, अचानक कलह और अचल सम्पत्ति व वाहनों की हानि होती है। दशेश से 8, 12 में हो या निर्बल हो तो कुभोजन और विदेश गमन होता है। 2, 7 भावेश हो तो अपमृत्यु का भय होता है।',
 'शिवसहस्रनाम का जप तथा स्वर्ण दान करना चाहिए।'),
('Moon','Saturn','hi',
 'केन्द्र, त्रिकोण, स्वक्षेत्र, स्वनवांश, उच्च या लाभ स्थान में (अथवा शुभ युक्त) हो तो शूद्रराजा की मित्रता से पुत्र, मित्र, धन-सम्पत्ति का लाभ होता है। व्यवसाय वृद्धि, अचल सम्पत्ति की वृद्धि, कल्याण और वैभव वृद्धि होती है।',
 '6, 8, 12, नीच या द्वितीय स्थान में हो तो शुरू में तीर्थयात्रा होती है परन्तु अनेक लोगों व शस्त्रों से भय/पीड़ा भी होती है। दशेश से केन्द्र/त्रिकोण में बली हो तो स्त्री व पुत्र से विरोध होता है। 2, 7 भावेश हो तो शरीर कष्ट होता है।',
 'मृत्युंजय का जप, और काली गाय या भैंस का दान करना चाहिए।'),
('Moon','Mercury','hi',
 'केन्द्र, त्रिकोण, 11 भाव, स्वक्षेत्र, उच्च या बली हो तो धनलाभ, राजसम्मान, प्रिय वस्त्रादि की प्राप्ति, विद्या, सज्जनसंगति, सन्तान प्राप्ति, व्यापार लाभ और विशिष्ट पद (अधिकार) की प्राप्ति होती है। दशेश से केन्द्र, त्रिकोण, लाभ या धन स्थान में हो तो विवाह, यज्ञ दीक्षा, मुक्ता मणि के अलंकार, आरोग्य लाभ और सुख प्राप्त होता है।',
 'दशेश से 6, 8, 12 या नीच में हो तो शरीर कष्ट, खेती या व्यवसाय की हानि, भूमिहानि, कारावास और स्त्री-पुत्र को पीड़ा होती है। 2, 7 भावेश हो तो ज्वरपीड़ा व बहुत भय होता है।',
 'मेषदान व विष्णु सहस्रनाम का पाठ करना चाहिए।'),
('Moon','Ketu','hi',
 'केन्द्र, त्रिकोण या 3, 11 में बली हो तो धनलाभ, सुख, स्त्री-पुत्रादि सुख और नीति सम्मत कार्य करने की प्रवृत्ति होती है (प्रारम्भ में धनहानि व पश्चात् सुख होता है)। दशेश से केन्द्र, त्रिकोण, लाभ में हो तो दशारम्भ में पशु धन की वृद्धि व सुख मिलता है।',
 'अन्तर्दशान्त में धन का नाश हो जाता है। पाप ग्रह से युक्त/दृष्ट या दशेश से 8, 12 में हो तो शत्रु द्वारा कार्यबाधा और अकस्मात् कलह होती है। 2, 7 भावगत हो तो देह कष्ट व भय होता है।',
 'मृत्युंजय जप करना चाहिए।'),
('Moon','Venus','hi',
 'केन्द्र, त्रिकोण, लाभ, स्वोच्च या स्वक्षेत्र में हो तो राज्यप्राप्ति, वाहन-वस्त्राभूषण की प्राप्ति, चौपाए पशुओं से लाभ, नया आवास निर्माण और सुन्दर स्त्री-स्वास्थ्य की प्राप्ति होती है। दशेश के साथ हो तो महल, सत्यकीर्ति और सम्पत्ति वृद्धि होती है। द्वितीय स्थान या 9, 11 भावेश युक्त हो तो धन-भूमि लाभ, इष्ट सिद्धि और देव-ब्राह्मणों की भक्ति होती है।',
 'नीच, अस्त, पापयुक्त या पापदृष्ट हो तो भूमिनाश, पुत्र-मित्रादि की हानि, स्त्रीहानि, चौपाए धन की हानि और राजद्वार में विरोध होता है। दशेश से 6, 8, 12 या पापयुक्त हो तो विदेश वास, दुःख, मृत्यु व चौरभय होता है। 2, 7 भावेश होने पर अपमृत्यु का भय होता है।',
 'रुद्रजप (रुद्रीय पाठ या तत्कृत अभिषेक), श्वेत गौदान और चाँदी का दान करना चाहिए।'),
('Moon','Sun','hi',
 'स्वोच्च, सिंह राशि, त्रिकोण या 2, 3, 11 भावों में हो तो नष्ट राज्य/पद की प्राप्ति, घर में कल्याण कार्य, मित्रों व अधिकारियों की कृपा से ग्राम व भूमि का लाभ, सन्तानोत्पत्ति और लक्ष्मी की कृपा प्राप्त होती है।',
 'अन्तर्दशा के अन्त में शरीर में शिथिलता, आलस्य व ज्वरादि कष्ट होता है। दशेश से 8, 12 में या पापयुक्त हो तो ज्वर, राजभय, चोर-विषैले जन्तुओं से भय और विदेश यात्रा में कष्ट होता है। 2, 7 भावेश हो तो ज्वर पीड़ा होती है।',
 'देवपूजा (शिवपूजा) करानी चाहिए।'),
('Mars','Mars','hi',
 'यदि मंगल लग्न से केन्द्र त्रिकोण, लाभस्थान, 2, 3 भाव में हो, शुभयुक्त हो या लग्नेश से युक्त हो, तो राजा व लक्ष्मी जी की कृपा से वैभव, नष्ट राज्य की प्राप्ति और पुत्रोत्सव होता है तथा घर में दूध की बहुतायत होती है। उच्चगत, स्वक्षेत्री या बली होने पर अचल सम्पत्ति की वृद्धि, दुधारू पशुओं का लाभ और बड़े लोगों के सहयोग से मनोरथ सिद्धि होती है।',
 'यदि 8, 12 भाव में हो या पापग्रह से युक्त/दृष्ट हो तो मूत्र रोग, घाव होने का भय, शरीर कष्ट की अधिकता, चोर-सर्प-राजा से भय और धन-धान्य की हानि होती है।',
 'यदि मंगल 2, 7 भावेश हो तो शरीर कष्ट होता है; इसके लिए साँड या बछड़े का दान, वृषोत्सर्ग (साँड छोड़ना) और रुद्रीयपाठ कराना चाहिए।'),
('Mars','Rahu','hi',
 'स्वोच्चगत, मूल त्रिकोणी, शुभयुक्त/दृष्ट, केन्द्र-त्रिकोण या लाभ स्थान में हो तो राजसम्मान, व्यवसाय से अधिक लाभ, गंगादि तीर्थों में स्नान और विदेशयात्रा के सुयोग होते हैं।',
 '8, 12 भाव में पापयुक्त/दृष्ट हो तो चोर-सर्प-चोट का भय, चौपाए पशुओं की हानि, वात-पित्त विकार और कारागृह निवास होता है। दूसरे स्थान में धन नाश व भय, तथा सातवें भाव में हो तो अपमृत्यु का भय होता है।',
 'नागपूजा, देवताओं की पूजा, ब्राह्मणभोजन और मृत्युंजय जप करने से स्वास्थ्य रक्षा होती है।'),
('Mars','Jupiter','hi',
 'केन्द्र, त्रिकोण, 2, 11 भावों में या उच्चादि नवांश में हो तो सत्कीर्ति, राजसम्मान, धन-धान्य वृद्धि, कल्याणकारी कार्य और स्त्री-पुत्रादि का लाभ होता है। महादशेश से केन्द्र-त्रिकोण-लाभ में हो या 1, 9, 10 भावेश/लग्नेश से युक्त हो तो जमीन-जायदाद, सुख-शान्ति, पशुधन और व्यवसाय में अधिक लाभ होता है।',
 '6, 8, 12 में, नीच, अस्त या पापयुक्त/निर्बल हो तो चोर-राज-सर्प भय, पित्त रोग, प्रेत बाधा, सेवकों व भाइयों को कष्ट होता है। 2, 7 भावेश हो तो अपमृत्यु व ज्वरादि से पीड़ा होती है।',
 'शिवसहस्रनाम का पाठ करना चाहिए।'),
('Mars','Saturn','hi',
 'स्वराशि, केन्द्र-त्रिकोण, मूल त्रिकोण में (या उससे केन्द्र में), उच्च, लग्नेश से युक्त या शुभ दृष्ट हो तो राज्य प्राप्ति, यशोवृद्धि, धान्य वृद्धि, पुत्र-पौत्र व पशुधन का सुख मिलता है। शनिवार व शनि मास में विशेष राजसम्मान मिलता है।',
 'नीच, शत्रुक्षेत्री, अस्त या 8, 12 में हो तो म्लेच्छ राजा/मुखिया से भय, धन-धान्य नाश, बन्धन और खेत-जंगल में रहना पड़ता है। 2, 7 भावेश (पापयुक्त) हो तो धननाश, राजद्वेष, मानसिक कष्ट, अग्नि-नृप भय, मृत्युभय और कारावास होता है। महादशेश से 8, 12 में पापयुक्त हो तो मृत्यु, वात विकार व विरोध होता है तथा केन्द्र/लाभ में हो तो विदेशवास व अपयश मिलता है।',
 'मृत्युंजय का जप करना चाहिए।'),
('Mars','Mercury','hi',
 'केन्द्र-त्रिकोण में हो तो मनोहारी प्रसंग, जप-दान, धर्मबुद्धि, यश, मधुर भोजन, कृषि फल और विशिष्ट वाहनों का सुख मिलता है। दशेश से केन्द्र-त्रिकोण, स्वोच्चादि में हो तो धन लाभ, राजसम्मान, सेनापतित्व, संगीत साधनों का सुख और घर में लक्ष्मी की कृपा होती है।',
 'नीच, अस्त या 6, 8, 12 में हो तो हृदयरोग, मान-हानि, बन्धन और स्त्री-पुत्र-धन-पशुओं की हानि होती है। मंगल-बुध साथ हों या दशेश से 6, 8, 12 में पापयुक्त हों तो क्रूर बुद्धि, शत्रु वृद्धि, मुक़दमेबाज़ी, लूटपाट का डर और कलह होती है। 2, 7 भावेश हो तो बड़ा रोग होता है।',
 'अश्वदान (वाहनदान) और विष्णुसहस्रनाम का पाठ करवाना चाहिए।'),
('Mars','Ketu','hi',
 'केन्द्र, त्रिकोण, 3, 11 भाव में या शुभयुक्त हो तो राजा की कृपा, बहुत सुख व धनलाभ होता है; आगे चलकर भूमि व पुत्र लाभ होता है। योगकारक के साथ या बलवान् हो तो पुत्र-यशोलाभ, घर में धन वृद्धि, सेनापतित्व और राजा से मित्रता होती है।',
 'दशा के प्रारम्भ में केवल थोड़ा फल मिलता है (दिए गए पाठ में इसके अतिरिक्त किसी विशिष्ट नकारात्मक फल का उल्लेख नहीं है)।',
 '(दिए गए पाठ में केतु के लिए किसी विशिष्ट उपाय का उल्लेख नहीं है)।'),
('Mars','Venus','hi',
 'केन्द्र, त्रिकोण, लाभ, स्वोच्च/स्वराशि या शुभ भावों का स्वामी हो तो राज्यप्राप्ति, बहुत सुख और अनेक वाहनों/भौतिक सुखों की प्राप्ति होती है। लग्नेश से सम्बन्ध हो तो आयु, ऐश्वर्य व स्त्री-पुत्रादि की वृद्धि होती है। दशमेश से युक्त हो तो पुण्य तीर्थ में स्नान और कूप-तडाग का निर्माण होता है।',
 'महादशेश से 6, 8, 12 या पापयुक्त हो तो कलह, दाँतों में रोग, चोर-जंगली जन्तुओं का भय, ज्वर, त्वचा विकार और बहुत दुःख होता है। 2, 7 भाव में हो तो शरीर रोग, अपमान, सन्ताप, धनहानि व गोधन का नाश होता है।',
 'आयु-आरोग्य वृद्धि के लिए सफेद गाय या दूध देने वाली भैंस का दान करना चाहिए।'),
('Mars','Sun','hi',
 'स्वोच्च, स्वक्षेत्र, मूल त्रिकोण, केन्द्र, लाभ या 9, 10 भावेश से युक्त हो तो वाहन-कीर्ति लाभ, पुत्रप्राप्ति, धन-धान्य वृद्धि, राजसम्मान, व्यवसाय लाभ और विदेश में बड़े लोगों से भेंट होती है।',
 'दशेश मंगल से 6, 8, 12 में या पापयुक्त हो तो शरीर-मन में कष्ट, कार्यहानि, सिर रोग और ज्वरादि/अतिसार भय होता है। 2, 7 भावेश हो तो पुत्र पीड़ा, सर्प, रोग व विष भय होता है।',
 'विधिवत् शान्ति करनी चाहिए, जिसमें सूर्य की उपासना और विष्णु या राम की अर्चना सम्मिलित है।'),
('Mars','Moon','hi',
 'वृष, कर्क राशि, केन्द्रगत या 1, 4, 7, 10 भावेशों से युक्त हो तो बहुत सांसारिक सुख, तडागादि/सार्वजनिक स्थानों का निर्माण, पुण्य-धर्म वृद्धि, विवाहादि उत्सव, माता-पिता/स्त्री-पुत्र सुख और बड़े लोगों के सहयोग से कार्यसिद्धि होती है।',
 'नीच, शत्रुक्षेत्री, 6, 8 में या दशेश से 6, 8 में हो तो स्त्री-पुत्रादि की मृत्यु, भूमि-पशुधन हानि और मरण/चोर भय होता है। 2, 7 भावेश हो तो अपमृत्यु का भय, देह में शिथिलता व मानसिक कष्ट होता है।',
 'दुर्गा व लक्ष्मी जी का पाठ करना चाहिए, तथा सफेद गाय या भैंस का दान करना चाहिए।'),
('Rahu','Rahu','hi',
 '4, 6, 8, 9 राशियों में हो तो राज सम्मान, वस्त्र-वाहन की प्राप्ति, व्यवसाय में सफलता, चौपाए जीवों से लाभ और पश्चिमी भू-भागों की यात्रा में सुख मिलता है। लग्न से 3, 6, 10, 11 भाव में हो या शुभ युक्त/दृष्ट, मित्रनवांश, उच्चादि या योगकारक हो तो राज्य लाभ, अधिक उत्साह, राजा से मित्रता, सुख-सम्पत्ति और स्त्री-पुत्रादि की वृद्धि होती है।',
 'लग्न से 8, 12 में हो या पापयुक्त/दृष्ट हो तो चोरादि से पीड़ा, चोट का भय, सरकारी आदमियों से विरोध, प्रिय जनों की हानि और स्त्री-पुत्रादि को पीड़ा होती है। 2, 7 भावेश हो या सप्तम में स्थित हो तो अपमृत्यु, रोग और कष्ट होते हैं।',
 'रुद्रीयजप, अघोर मन्त्र से आराधना/जप और दानादि करना चाहिए।'),
('Rahu','Jupiter','hi',
 'केन्द्र, त्रिकोण, स्वोच्च, स्वक्षेत्र, उच्च या स्वनवांश में हो तो पद प्राप्ति, मन में धैर्य, शत्रु नाश, राजा से प्रेम, धन-वाहन लाभ, पशु धन वृद्धि, पश्चिम दिशा की सफल यात्रा और तीर्थयात्रा होती है। दशापति से केन्द्र, त्रिकोण, लाभ, धन या तृतीय में बली हो तो घर, जमीन, जायदाद और भोजन-वस्त्र की वृद्धि होती है।',
 'नीच, अस्त, 6, 8, 12 भाव में, शत्रुक्षेत्री या पापयुक्त हो तो धनहानि, कार्य में विघ्न, मानहानि, परिवार को पीड़ा और हृदयरोग होता है (परन्तु राजकीय कार्य मिलता है)। दशापति से 6, 8, 12 या पापयुक्त हो तो धनहानि और शरीर कष्ट होता है; दशा के अन्त में ज्येष्ठ भाई का शोक व माता-पिता को कष्ट होता है। 2, 7 भावेश होने पर दुर्घटना या अपमृत्यु का भय होता है।',
 'सोने की शिवप्रतिमा का दान और शिवपूजा करानी चाहिए।'),
('Rahu','Saturn','hi',
 'केन्द्र, त्रिकोण, स्वोच्च, मूल त्रिकोण या 9, 11 भाव में हो तो राज सेवा, विवाहोत्सव, पुण्यकार्य, बगीचा/तड़ाग निर्माण, शूद्र राजा के सहयोग से इष्टसिद्धि, गोधन संग्रह और स्वदेश वापसी से सुख होता है।',
 'नीच, शत्रुक्षेत्री, 8, 12 भाव में हो तो नीच लोगों व राजा से डर, शत्रु भय, परिवार को पीड़ा, हिस्सेदारों से विवाद और मुकदमेबाजी होती है। दशेश से 6, 8, 12 या पापयुक्त हो तो हृदयरोग, मानहानि, वृथा भ्रमण, गुल्म रोग, कुभोजन और अपनी जाति पर कष्ट आता है। पश्चिम दिशा की यात्रा से धन हानि होती है। 2, 7 भावेश होने पर अपमृत्यु होती है।',
 'शान्ति के लिए काली गाय या भैंस का दान करें।'),
('Rahu','Mercury','hi',
 'नवम, स्वराशि, स्वोच्च, केन्द्र, पंचम या बली हो तो राजयोग, घर में कल्याणकार्य, व्यापार से धनलाभ, विद्या-वाहन लाभ, विवाह, चौपाए जीवों से लाभ और स्त्री-सुख मिलता है। दशेश से केन्द्र, 3, 9, 11 या दशम में हो तो आरोग्य, उत्साह, मनोरथसिद्धि, यश, यज्ञ और दान-धर्म के योग होते हैं।',
 '6, 8, 12 में, शनि से युक्त/दृष्ट या दशेश से 6, 8, 12 में पापयुक्त हो तो देव-ब्राह्मणों की निन्दा, भाग्यहीनता, दुर्बुद्धि, चोर-सर्प-राज भय, अकस्मात् कलह और परिवार को पीड़ा होती है। 2, 7 भावेश हो तो अपमृत्यु का भय होता है।',
 'अपमृत्यु को दूर करने के लिए विष्णु-सहस्रनाम का जप करना चाहिए।'),
('Rahu','Ketu','hi',
 'शुभयुक्त या शुभ दृष्ट हो तो शरीर सुख, धन लाभ, राज सम्मान और घर में शुभता रहती है। लग्नेश से सम्बन्ध करे या केन्द्र-त्रिकोण में हो तो इष्ट सिद्धि, लाभ और चौपाए जीव से लाभ होता है।',
 'भ्रमण, राजा से भय, वात ज्वर और चौपाए से हानि होती है। अष्टमेश से युक्त हो तो शरीर कष्ट व मानसिक व्यथा होती है। अष्टम, द्वादश या बलहीन हो तो अनेक रोग, चोर-सर्प-चोट भय, माता-पिता से वियोग और भाइयों से द्वेष होता है। 2, 7 भावेश से सम्बन्ध होने पर शरीर कष्ट होता है।',
 'दोष निवृत्ति के लिए बकरे आदि का दान करना चाहिए।'),
('Rahu','Venus','hi',
 'केन्द्र, त्रिकोण, लाभ या बलवान् हो तो ब्राह्मण की सहायता से धनप्राप्ति, पशु लाभ, पुत्रोत्सव, मांगलिक कार्य और राजसम्मान मिलता है। 12, 2, 7 राशि/नवांश में हो तो नए घर का निर्माण, मधुर भोजन, मित्र संगति, दान-धर्म, वाहन-वस्त्र लाभ और विवाह/यज्ञोपवीत होता है। दशेश से केन्द्र, त्रिकोण, लाभ या दशम में हो तो घर का सुख, सुगन्धित वस्त्र, गानवाद्य सुख (आमोद-प्रमोद) और प्रिय वस्तु का लाभ होता है।',
 '6, 8, 12, नीच, शत्रुराशि या शनि/मंगल/राहु युक्त हो तो रोगभय, अचानक कलह, पिता/पुत्र वियोग, हिस्सेदारों से कलह, मृत्यु और शूलरोग होता है। दशेश से 6, 8, 12 या पापयुक्त हो तो प्रमेह (मधुमेह/रुधिर विकार), मूत्र रोग, सिर दर्द, कारागृह वास, राजदण्ड और विप्र-सर्प-नृप-चोर से पीड़ा होती है। 2, 7 भावेश हो तो स्त्री-पुत्र नाश, निज कष्ट व दुर्घटना भय होता है।',
 'शान्ति के लिए दुर्गा व लक्ष्मी का जप करना चाहिए।'),
('Rahu','Sun','hi',
 'स्वोच्च, स्वक्षेत्र, केन्द्र, त्रिकोण, लाभ, उच्च/स्वनवांश या शुभ दृष्ट हो तो राजा से सम्बन्ध, धन-धान्य की समृद्धि और छोटे स्थान/ग्राम में सम्मान मिलता है (परन्तु कम लाभ व कम सम्मान होता है)। 1, 9 भाव युक्त या दशमेश दृष्ट हो तो राजा का आश्रय, कीर्ति, विदेश यात्रा, राजयोग, कीमती वाहन और पुत्र समृद्धि होती है। दशेश से केन्द्र, त्रिकोण, तृतीय या लाभ में हो तो विदेश में उत्तम सम्मान व कल्याण की प्राप्ति होती है।',
 'दशेश से 6, 8, 12 या नीचगत हो तो ज्वर, पेट के रोग, कलह, राजा से विरोध, जगह छोड़ने के अवसर, शत्रु वृद्धि और राजा-अग्नि-चोर से पीड़ा होती है। 2, 7 भावेश हो तो किसी बड़े रोग का शिकार होना पड़ता है।',
 'बड़े रोग व अरिष्ट से बचने के लिए सूर्य प्रणाम और सूर्य नमस्कारादि से सूर्यशान्ति करनी चाहिए।'),
('Rahu','Moon','hi',
 'स्वक्षेत्र, स्वोच्च, केन्द्र, त्रिकोण, लाभ, मित्रराशि या शुभयुक्त हो तो राज पदवी, धनलाभ, आरोग्य, और मित्र-स्त्री-पुत्र की वृद्धि होती है। पूर्ण चन्द्रमा होने पर पूरा फल, राजप्रीति, तीव्रगति वाहन (घोड़े आदि) की प्राप्ति होती है। दशेश से 4, 9, केन्द्र या लाभ में हो तो लक्ष्मी की विशेष कृपा, कल्याणकारी कार्य, सर्वकार्य सिद्धि, धनधान्य वृद्धि व सत्कीर्ति मिलती है।',
 'दशेश से 6, 8, 12 में या बलहीन हो तो पिशाच-वन जन्तु भय, घर-खेत की हानि, रास्ते में चोरी, अधिक चोट, पेट की विषमता व अधिक भूख होती है। 2, 7 भावेश हो तो शरीर कष्ट होता है।',
 'शान्ति के लिए सफेद गाय या भैंस का दान ब्राह्मण को करें, तथा देवी की आराधना करें।'),
('Rahu','Mars','hi',
 'लग्न से त्रिकोण, लाभ, केन्द्र, शुभयुक्त, स्वोच्च या स्वक्षेत्र में हो तो खोई हुई सम्पत्ति/पदवी की प्राप्ति, अचल-चल सम्पत्ति सुख, सन्तान सुख, भूषण व वाहन की प्राप्ति होती है। दशेश से केन्द्र, कोण, तृतीय या लाभ में हो तो लाल वस्त्र प्राप्ति, राजदर्शन, पुत्रों-भाइयों व स्वामी की समृद्धि, सेनापतित्व और बहुत सुख मिलता है।',
 'दशेश से 6, 8, 12 या पापयुक्त हो तो पुत्र-स्त्री व भाइयों को कष्ट, स्थान परिवर्तन, बन्धु विरोध, चोर-सर्प-चोट भय और शरीर कष्ट होता है (प्रायः दशा के आरम्भ में कष्ट व पश्चात् शान्ति रहती है)। 2, 7 भावेश हो तो शरीर में आलस्य व भय होता है।',
 'शान्ति के लिए गाय व साँड का दान करना चाहिए।'),
('Jupiter','Jupiter','hi',
 'स्वक्षेत्री, स्वोच्चगत, केन्द्र या त्रिकोण में होने पर जातक अनेक राजाओं द्वारा पूजित या सम्पन्न होता है। पशुधन (गाय-भैंस), वस्त्र, वाहन, आभूषण की प्राप्ति, नए बँगले/घर का निर्माण, भाग्य व परिश्रम का फल, ब्राह्मणों के मुखिया द्वारा सम्मान, राजदर्शन, तथा स्त्री-पुत्रादि का लाभ होता है।',
 'नीच नवांश, नीच राशि, या 6, 8, 12 भाव में होने पर नीच लोगों की संगति, बहुत दुःख, उत्तराधिकार का विवाद, मालिकों से टकराव, स्त्री-पुत्रों का वियोग और धन-धान्य की हानि होती है। 7 भावेश होने पर शरीर कष्ट और अपमृत्यु का भय होता है।',
 'शान्ति के लिए शिव सहस्रनाम का जप, सहस्ररुद्राभिषेक और गोदान करना चाहिए।'),
('Jupiter','Saturn','hi',
 'स्वोच्च, स्वक्षेत्र, मित्र क्षेत्र, केन्द्र, त्रिकोण या लाभ स्थान में (या बलवान) होने पर राज्य लाभ, महान् सुख, वस्त्राभूषण-धन-धान्य की प्राप्ति, स्त्री-पुत्र-मित्र लाभ, वाहन (विशेषकर नरवाहन/पालकी) व भूमि का लाभ होता है। नीले वस्त्रों व काले घोड़े का लाभ तथा पश्चिम दिशा की यात्रा से राजा से भेंट व अनेक वाहनों का लाभ होता है।',
 '6, 8, 12 भाव, नीच, अस्त या शत्रुक्षेत्री होने पर धन-धान्य का नाश, ज्वर-घाव पीड़ा, मनोविकार, स्त्री-पुत्र व सेवकों को कष्ट, पशुहानि और अपने लोगों से द्वेष होता है। दशेश गुरु से 6, 8, 12 या पापयुक्त होने पर बन्धु-मित्रों से विरोध, प्रयत्नों की असफलता और शरीर कष्ट होता है। 2, 7 भावेश होने पर अपमृत्यु होती है।',
 'विष्णु सहस्रनाम का पाठ तथा काली गाय या भैंस का दान करना चाहिए।'),
('Jupiter','Mercury','hi',
 '1, 4, 5, 7, 9, 10, 11 भावों में, स्वक्षेत्र, उच्च या बृहस्पति के साथ होने पर धन लाभ, शरीर सुख, राज्यप्राप्ति, इष्टसिद्धि और वाहन-पशु-वस्त्र की बहुतायत होती है। दशेश से 5, 9, केन्द्र या उच्चगत होने पर स्वदेश में धन लाभ, माता-पिता का पूरा सुख और राजा के सहयोग से कार्य सिद्ध होते हैं।',
 'मंगल की दृष्टि होने पर शत्रु वृद्धि, व्यवसाय हानि और ज्वर-अतिसार पीड़ा होती है। दशेश से 6, 8, 12 में, पापयुक्त व शुभदृष्टिहीन होने पर धन-धान्य हानि, चोर भय, घाव, नेत्र रोग और अनेक स्थानों पर वृथा भ्रमण होता है। लग्न से 6, 8, 12 या पापयुक्त होने पर अचानक कलह, मुकदमों में पराजय, पशु हानि, दुर्घटना व शत्रुओं से कलह होती है। 2, 7 भावेश होने पर अपमृत्यु का विशेष भय होता है। (शुभयुक्त/दृष्ट होने पर आरम्भ में शुभ, परन्तु अन्त में हानि होती है)।',
 'विष्णु सहस्रनाम का पाठ करना चाहिए (आयु व सौभाग्य वर्धक)।'),
('Jupiter','Ketu','hi',
 'दशेश से 5, 9, 4, 10 भाव में होने पर नरवाहन (पालकी), हाथी-घोड़े की प्राप्ति, महाराजाओं की प्रसन्नता से इष्ट सिद्धि, व्यवसाय लाभ, पशुधन वृद्धि और यवन राज की सहायता से धन-वस्त्र का लाभ होता है।',
 'शुभ ग्रह युक्त होने पर भी कम सुख-लाभ, निंदित/पराया/श्राद्ध भोजन और पापपूर्ण कार्यों से धन लाभ होता है। दशेश से 6, 8, 12 में पापयुक्त होने पर राजकोप, धनहानि, बन्धन, रोग, पिता/भाइयों से द्वेष और मनोविकार होते हैं। 2, 7 भावेश/मारकेश युक्त होने पर शरीर कष्ट होता है।',
 'मेषदान (बकरे का दान) और मृत्युंजय का जप करना चाहिए।'),
('Jupiter','Venus','hi',
 'जन्म कुण्डली में 1, 4, 7, 5, 9, 10, 11 राशियों, स्वक्षेत्र या शुभ ग्रह युक्त होने पर नरवाहन (पालकी), राजा की सहायता से लाभ, पूर्वदिशा की यात्रा में धन लाभ, माता-पिता को सुख और देव-गुरु भक्ति होती है। अन्नदान व प्याऊ/स्मृतिद्वार निर्माण से पुण्य प्राप्त होता है। दशेश से केन्द्र, धन या भाग्य भाव में होने पर धन-धान्य-वाहन-पुत्र-पशु लाभ, राजा से भेंट, विद्वानों से मिलाप और उत्तम भोजन मिलता है।',
 '6, 8, 12 या नीचगत होने पर कलह, बन्धुओं से असन्तुलित सम्बन्ध और परिवार को पीड़ा होती है। शनि, मंगल या राहु से युक्त होने पर सरकार/ससुर/भाइयों से विवाद, स्त्री के कारण कलह और धन-धान्य की हानि होती है। 2, 7 भावेश होने पर धनहानि, स्त्री के कारण या हवा से रोग व अपमृत्यु का भय होता है।',
 'शान्तिकर्म तथा सफेद गाय या भैंस का दान करना चाहिए।'),
('Jupiter','Sun','hi',
 'उच्चगत, सिंहस्थ, लग्न/दशेश से केन्द्र, त्रिकोण या 2, 3, 11 भाव में या बलवान होने पर तुरन्त धन लाभ (परन्तु व्यय भी उल्लिखित है), राजसम्मान, वाहन-पशु लाभ, पुत्र जन्म और मित्र राजा की सहायता से सफलता मिलती है।',
 'लग्न या दशेश से 6, 8, 12 में होने पर सिर-ज्वर पीड़ा, अच्छे कार्यों में हानि, पाप वृद्धि, लोगों से मनमुटाव, बन्धु वियोग और अचानक कलह होती है। 2, 7 भावेश होने पर अपमृत्यु का भय होता है।',
 'आदित्यहृदय स्तोत्र का पाठ करना चाहिए।'),
('Jupiter','Moon','hi',
 'केन्द्र, त्रिकोण, एकादश, स्वोच्च/स्वराशि, पूर्ण या बलवान (या दशेश से इन भावों में) होने पर राजसम्मान, स्त्री-पुत्र सुख, दूध के पदार्थों का भोजन, सत्कार्य, धन लाभ, बड़े लोगों की सहायता और दान-धर्म होता है।',
 'लग्न या दशेश से 6, 8, 12 में, पापयुक्त, क्षीण या निर्बल होने पर मान-बन्धु-धन हानि, विदेश से पलायन, राजा/चोर से पीड़ा, उत्तराधिकारियों से विवाद, माता व मामा का कष्ट/वियोग होता है। 2, 6 (तथा 7) भावेश होने पर शरीर कष्ट होता है।',
 'शरीर कष्ट व दोष निवृत्ति के लिए दुर्गापाठ कराना चाहिए।'),
('Jupiter','Mars','hi',
 'लग्न से केन्द्र, त्रिकोण (या लाभ), स्वोच्च, स्वराशि या उच्च नवांश में होने पर विद्या, विवाह, ग्राम-भूमि लाभ और जनसमर्थन से सफलता मिलती है। दशेश से केन्द्र, त्रिकोण, 2, 11 भावों या शुभ युक्त/दृष्ट होने पर धन-धान्य वृद्धि, मिष्टान्न दान, राजप्रीति, स्त्री-पुत्र सुख और पुण्यतीर्थों में स्नान होता है (उत्तरार्ध में बहुत सुख होता है)।',
 'दशेश से 8, 12, नीच या पापदृष्ट/युक्त होने पर धन-धान्य-भवनादि का नाश, रोग, भय, नेत्र कष्ट और पूर्वार्ध में बहुत दुःख होता है। 2, 7 भावेश होने पर मनोविकार व शरीर में शिथिलता होती है।',
 'साँड या बछड़े का दान करना चाहिए।'),
('Jupiter','Rahu','hi',
 'केन्द्र, उच्च, मूलत्रिकोण, नवम, केन्द्रेश-त्रिकोणेश युक्त या शुभ युक्त/दृष्ट होने पर धन-धान्य लाभ (विशेषकर पहले 5 महीनों में), देश/ग्राम का अधिकार, यवन सम्राट् से भेंट, सेनापतित्व, दूर देश यात्रा और रामेश्वर (सेतु) स्नान होता है।',
 'दशेश से 8, 12 या पापयुक्त होने पर चोर-चोट-सर्प भय, राजा से प्रतिकूलता, घरेलू समस्याएँ, भाइयों/उत्तराधिकारियों से विवाद, घर में अमंगल और छोटे/काल्पनिक रोगों से पीड़ा होती है। 2, 7 भाव में होने पर शरीर कष्ट होता है।',
 'मृत्युंजय जप, बकरे का दान और देवताओं की पूजा करनी चाहिए।'),
('Saturn','Saturn','hi',
 'मूलत्रिकोणी, स्वक्षेत्री, उच्चगत, केन्द्र, त्रिकोण, लाभ या राजयोग कारक ग्रह से युक्त होने पर राज्य लाभ, खूब सुख, स्त्री-पुत्रादि की वृद्धि और कई वाहनों का सुख मिलता है। भौतिक समृद्धि, सेनापतित्व (अधिकार प्राप्ति), चौपाए पशुओं व भूमि का लाभ होता है तथा दशा के अन्त में शुभ फल प्राप्त होते हैं।',
 '8, 12 में, नीचगत या पापयुक्त होने पर दशारम्भ में राज भय, विष-शस्त्रादि पीड़ा, रक्त बहना, गुल्म रोग और दस्त आदि होते हैं। दशा के मध्य में चोर भय, स्थान/देश त्याग और मनोविकार होते हैं। 2, 7 भावेश होने पर अपमृत्यु का भय होता है।',
 'अपमृत्यु व अनिष्ट निवारण के लिए मृत्युंजय मन्त्र का जप करना चाहिए।'),
('Saturn','Mercury','hi',
 'केन्द्र या त्रिकोण में होने पर सम्मान, यश, विद्या-धन लाभ, स्वदेश में सुख, यज्ञादि की सम्पन्नता और राजयोग प्राप्त होता है। शरीर सुख, उत्साह, घर में कल्याणकारी कार्य, सेतुस्नान, तीर्थयात्रा, व्यापार से लाभ, पुराण श्रवण और मिष्ठान्न भोजन के फल मिलते हैं।',
 '6, 8, 12 भाव, नीच, अस्त या सूर्य/मंगल/राहु के साथ (या दशेश से 6, 8, 12 में) होने पर दशा के मध्य और अन्त में रोग पीड़ा, सब कार्यों का नाश, मन में व्याकुलता और भय होता है। 2, 7 भावेश होने पर शरीर कष्ट होता है।',
 'दोष शान्ति के लिए विष्णु सहस्रनाम का पाठ व अन्न दान करना चाहिए।'),
('Saturn','Ketu','hi',
 'लग्नेश से युक्त होने पर अन्तर्दशा के पूर्वार्ध में सुख व धन का लाभ होता है। दशेश से केन्द्र, त्रिकोण, तृतीय या एकादश में होने पर सामर्थ्य वृद्धि, धर्म बुद्धि व राजा से समागम होता है।',
 'शुभ फलद/शुभ ग्रह से दृष्ट, स्वोच्च या केन्द्र-त्रिकोण में होने पर भी स्थान परिवर्तन, दरिद्रता, भय, पुत्र-स्त्री व स्वामी को कष्ट तथा विदेशगमन होता है। लग्न या दशेश से 8, 12 में होने पर अपमृत्यु भय, खराब भोजन, शीत ज्वर, घाव और स्त्री-पुत्र का वियोग होता है। 2, 7 भाव में होने पर शरीर कष्ट होता है।',
 'मेष (बकरे) का दान करना चाहिए।'),
('Saturn','Venus','hi',
 'उच्च, स्वक्षेत्र, केन्द्र, त्रिकोण, लाभ या शुभयुक्त होने पर स्त्री-पुत्र-धन प्राप्ति, आरोग्य, घर में महान् उत्सव, राज्य लाभ, इष्टसिद्धि और राजमान्यता मिलती है। विदेशों से वस्त्र लाभ, सफेद घोड़े की सवारी और दुधारू पशुओं की प्राप्ति होती है। दशेश से केन्द्र, लाभ या त्रिकोण में होने पर राजा से प्रीति, तीर्थयात्रा, शास्त्रार्थ व वेदान्त श्रवण का सुयोग मिलता है।',
 'नीच, अस्त, 6, 8, 12 में होने पर स्त्री कष्ट, मन क्लेश, स्थान नाश, मनोविकार और लोगों का विरोध सहना पड़ता है। दशेश से 6, 8, 12 में होने पर ज्वर, कुलाचार के विरुद्ध कार्य, दाँत/हृदय/गुप्तांगों में दर्द, जल भय, वृक्ष से गिरना और भाइयों से विरोध होता है। 2, 7 भावेश होने पर स्वयं को कष्ट होता है।',
 'दुर्गा पाठ, और सफेद गौ या भैंस का दान करना चाहिए।'),
('Saturn','Sun','hi',
 'उच्च, स्वक्षेत्र, केन्द्र-त्रिकोण, नवमेश से युक्त या शुभ दृष्ट होने पर अपने स्वामी/अधिकारी की ओर से सुख, घर में बढ़ोत्तरी, पुत्रादि सुख, वाहन-पशु लाभ और गाय के दूध की अधिकता होती है।',
 'लग्न या दशेश से 8, 12 में होने पर हृदयरोग, मानहानि, पद की हानि, इष्टजनों का वियोग, असफलता, ताप ज्वर और अपने निजी व्यक्ति का शोक होता है। 2, 7 भावेश होने पर शरीर कष्ट होता है।',
 'दोष शान्ति के लिए सूर्य पूजा करानी चाहिए।'),
('Saturn','Moon','hi',
 'गुरु की दृष्टि होने, उच्च/स्वक्षेत्री, पूर्ण या शुभ युक्त होने पर राजाओं से मित्रता, वाहनादि सुख, सौभाग्यवृद्धि, नौकरों को पालने का स्तर, मातृ-पितृ कुल में सुख एवं पशुवृद्धि होती है। (दशेश से केन्द्र, त्रिकोण, लाभ में होने पर भी सुख व धन लाभ मिलता है)।',
 'क्षीण, पापयुक्त, पापदृष्ट, नीच या क्रूर नवांश में होने पर महान् कष्ट, राजकोप, धन हानि, माता-पिता का वियोग, सन्तान को कष्ट, असमय भोजन और दवा खाने के योग बनते हैं। दशेश से 8, 12 या निर्बल होने पर आलस्य, रोग, स्थान नाश व शत्रु वृद्धि होती है। 2, 7 भावेश होने पर शरीर में शिथिलता आती है।',
 'तिल से हवन करें, गुड़-घी-दही-चावल का दान करें तथा सफेद गाय या भैंस का दान करें।'),
('Saturn','Mars','hi',
 'केन्द्र, त्रिकोण, लाभस्थान, स्वोच्च, स्वक्षेत्र या दशेश/लग्नेश के साथ होने पर दशारम्भ में सुख, धनलाभ, राजा से प्रीति, सेनापतित्व, कृषि-पशु धन की वृद्धि और नए स्थान का निर्माण होता है।',
 'नीच, अस्त, 8वें या पापदृष्ट होने पर धनहानि, चोर-सर्प-शस्त्र भय, ट्यूमर (ग्रंथि) रोग, भाइयों/मित्रों को कष्ट, विदेशगमन और धन व्यय होता है। 7, 8 भावेश या द्वितीयस्थ होने पर अपमृत्यु भय, नानाकष्ट व पराजय होती है।',
 'शान्तिकार्य, हवन और साँड़ (वृष) का दान करना चाहिए।'),
('Saturn','Rahu','hi',
 'लग्नेश/योगकारक के साथ, स्वोच्च, स्वक्षेत्र, केन्द्र या दशेश से एकादश में होने पर आरम्भ में सुख, धन-जायदाद लाभ, देव-ब्राह्मणों की भक्ति और तीर्थयात्रा होती है। मेष, कन्या, कर्क, वृष, मीन, धनु या सिंह में होने पर अपूर्व ऐश्वर्य और राजसम्मान की प्राप्ति होती है।',
 'सामान्यतः कलह, मानसिक/शारीरिक कष्ट, पुत्र से द्वेष, रोगभय, धन व्यय, राजभय और खेत-मकान की हानि होती है। दशा मध्य में राजभय व पुत्रों-मित्रों से विरोध होता है। 2, 7 भावेशों के साथ होने पर शरीर कष्ट होता है।',
 'मृत्युंजय जप, मेषदान और वृषभदान करना चाहिए।'),
('Saturn','Jupiter','hi',
 'केन्द्र, त्रिकोण, लाभ, स्वोच्च, स्वक्षेत्र या लग्नेश से युक्त होने पर सफलता, धन-वाहन की प्राप्ति, सम्मान, देवताओं व गुरु की भक्ति, विद्वानों से समागम और स्त्री-पुत्र का लाभ होता है। दशेश से 1, 2, 4, 5, 7, 9, 10, 11 भावों में होने पर वैभव, भोजन-वस्त्र का सुख, यज्ञादि कार्यों का सम्पादन, अन्नदान व वेदान्त श्रवण के अवसर मिलते हैं।',
 '6, 8, 12, नीच या पापयुक्त होने पर निजी व्यक्ति की मृत्यु, धन-धान्य का विनाश, सरकारी स्थानों पर विरोध, कार्यहानि व त्वचा रोग (कुष्ठ) होता है। दशेश से 6, 8, 12 या निर्बल होने पर बन्धुओं से द्वेष, कलह, पदहानि, कुभोजन, कारावास और राजदण्ड से धनहानि होती है। 2, 7 भावेश होने पर शरीर कष्ट व किसी अपने की हानि होती है।',
 'शिव सहस्रनाम का जप व स्वर्ण दान करना चाहिए।'),
('Mercury','Mercury','hi',
 'स्वोच्च, स्वक्षेत्र, मूलत्रिकोण, शुभयुक्त, शुभदृष्ट, केन्द्र या त्रिकोण में होने पर मुक्ता-विद्रुम (मोती-मूँगा) आदि मणियों व रत्नों की प्राप्ति, ज्ञान-कार्य-विद्या की वृद्धि, महत्त्व वृद्धि, नए राजा/अधिकारी से मिलन, वैभव, स्त्री-पुत्रादि की वृद्धि और माता-पिता का सुख होता है।',
 'नीच, अस्त, पापयुक्त या अशुभ भाव (6, 8, 12) में होने पर धन-धान्य की हानि, अपने लोगों से विरोध, शूल रोग की उत्पत्ति और राजकीय कार्यों में अति व्यस्त रहने से व्याकुलता होती है। 2, 7 भावेश होने पर स्त्री को कष्ट, अपने निजी जन की हानि और वातशूल रोग की सम्भावना होती है।',
 'दोष शान्ति के लिए विष्णु सहस्रनाम के पाठ करने चाहिए।'),
('Mercury','Ketu','hi',
 '1, 4, 5, 7, 9, 10 भावों में, शुभ युक्त/दृष्ट, लग्नेश से युक्त, योग कारक से सम्बन्धित, या दशेश से केन्द्र/लाभगत होने पर शरीर सुख, धन का थोड़ा लाभ, भाइयों का स्नेह और चौपाए धन का लाभ होता है।',
 'दशेश बुध से 8, 12 भाव में और पापयुक्त होने पर वाहन से पतन, पुत्र क्लेश, चोर-राज भय, पापकर्म का उदय, बिच्छू आदि जीवों/विषैला संक्रमण का भय, नीच लोगों से कलह, शोक, रोग, दुःख और नीच संगादि होते हैं। 2, 7 भाव या भावेशों से सम्बन्ध होने पर शरीर कष्ट होता है।',
 'दोष शान्ति के लिए बकरे का दान करना चाहिए।'),
('Mercury','Venus','hi',
 'केन्द्र, लाभ या त्रिकोण में होने पर अच्छे समाचार, पुण्य-धार्मिक कार्य, मित्र-राजा के सहयोग से इष्टलाभ, और स्थान व सम्पत्ति का लाभ-सुख होता है। दशेश से केन्द्रादि में होने पर तुरन्त लक्ष्मी, राजमान, सम्पत्ति प्राप्ति, बावड़ी-कूप-तड़ाग का निर्माण, दान-धर्म, व्यवसाय से अधिक लाभ और धन-धान्य की समृद्धि होती है।',
 'दशेश बुध से 6, 8, 12 में या निर्बल होने पर हृदय रोग, मान हानि, ज्वरातिसार से पीड़ा, अपने लोगों से विछोह, स्वयं को कष्ट और मानसिक सन्ताप होता है। 2, 7 भावेश होने पर अपमृत्यु होती है।',
 'दोष निवारणार्थ दुर्गा पाठ करने चाहिए।'),
('Mercury','Sun','hi',
 'स्वोच्चादि राशियों, 2, 5, 9, 11 भावों, केन्द्र या उच्च/स्वनवांश में होने पर राजा के महल में जाने का अवसर, सौभाग्य और मित्र (समर्थपुरुष) के सहयोग से सुख होता है। मंगल की दृष्टि होने पर आरम्भ में भूमि लाभ होता है। लग्नेश की दृष्टि होने पर बहुत सुख, धनलाभ, गाँव-जमीन-जागीर की प्राप्ति और भौतिक सुख मिलता है।',
 'लग्न या दशेश से 6, 8, 12 में, शनि-मंगल-राहु से युक्त या निर्बल होने पर चोर-शस्त्र-अग्नि पीड़ा, पित्तवृद्धि, शिरोरोग, मनस्ताप और अपने प्रिय व्यक्ति का वियोग होता है। 2, 7 भावेश होने पर अपमृत्यु होती है।',
 'शान्ति के लिए यथाविधि उपाय (सूर्य पूजा, आदित्य हृदय आदि) करना चाहिए।'),
('Mercury','Moon','hi',
 'केन्द्र, त्रिकोण, उच्च, स्वक्षेत्र, गुरु दृष्ट/युत या योग कारक होने पर विशेष उत्तम फल, स्त्री-पुत्र-वस्त्र-वाहन का लाभ, नया घर, मधुर भोजन, आमोद-प्रमोद, शास्त्रों में परिश्रम, दक्षिण दिशा की सफल यात्रा, विदेशी वस्त्रों-मोती-माणिक्य का लाभ और साफ धुले वस्त्रों का प्रयोग होता है। (दशेश से केन्द्र, त्रिकोण, 3, 11 में होने पर आरम्भ में तीर्थयात्रा, धैर्य-उत्साह और विदेश से धन लाभ होता है)।',
 'नीच या शत्रु क्षेत्र में होने पर शरीर कष्ट होता है। दशेश से 6, 8, 12 या पापयुक्त होने पर चोर-राज-अग्नि भय, स्त्री समागम से कष्ट, पाप कार्य, धनहानि और कृषि-पशु-वाहन की हानि होती है। 2, 7 भावेश होने पर शरीर कष्ट होता है।',
 'दोष शान्ति के लिए दुर्गापाठ और वस्त्र दान करना चाहिए।'),
('Mercury','Mars','hi',
 'केन्द्र, त्रिकोण, उच्च, स्वक्षेत्र या लग्नेश के साथ होने पर राजा की कृपा से विपत्ति-निवारण, घर में सुख, लक्ष्मी वृद्धि, खोया राज्य-सम्पत्ति पुनः प्राप्त, पुत्र जन्म, गोधन वृद्धि, हाथी-घोड़े की प्राप्ति, राजप्रीति और स्त्री का उत्तम सुख होता है। दशेश से केन्द्र, त्रिकोण, 11 या शुभ दृष्ट होने पर धन लाभ, शरीर सुख, यशो वृद्धि और भाइयों में लोकप्रियता मिलती है।',
 'नीच, 8, 12 भाव, पापदृष्ट/युत होने पर शरीर-मानसिक कष्ट, परिश्रम की असफलता, अपने स्थान पर धान्यादि का नाश, गाँठ या घाव से पीड़ा और साध्य रोग होते हैं। दशेश से 8, 12 या पापयुक्त होने पर आरम्भ में महान् क्लेश, राज-अग्नि-चोर भय, पुत्र-मित्र विरोध और स्थान परिवर्तन होता है (परन्तु मध्य में सुख-धन लाभ होता है); अन्त में राजभय व स्थानहानि होती है। 2, 7 भावेश होने पर अपमृत्यु का भय होता है।',
 'दोष निवारण हेतु गोदान व मृत्युंजय जप कराएँ।'),
('Mercury','Rahu','hi',
 '1, 4, 7, 10, 5, 9, 11 भावों या 2, 4, 6, 11 राशियों में होने पर राज-सम्मान, कीर्ति, धन लाभ, तीर्थ स्नान, देव दर्शन (मन्त्र सिद्धि), यज्ञ की सम्पन्नता और वस्त्र लाभ होता है (आरम्भ में शरीर कष्ट परन्तु अन्त में सुख होता है)। लग्न से 3, 6, 10, 11 में शुभ ग्रह के साथ होने पर राजा से वार्तालाप और नए अधिकारी/राजा की प्राप्ति होती है।',
 '8, 12 में होने पर धननाश, आरम्भ में शरीर कष्ट, वात विकार, ज्वर और अजीर्ण होता है। दशेश से 8, 12 में पापयुक्त होने पर कठोर राजकीय कार्य, स्थान नाश/परिवर्तन, भय, बन्धन, रोग, अपने लोगों से व्यथा, हृदय रोग और मान-धन हानि होती है। 2, 7 भाव में होने पर अपमृत्यु का भय होता है।',
 'दुर्गा व लक्ष्मी का पाठ (सप्तशती मध्यम चरित्र का पाठ) और दूधारू गाय/भैंस का दान करना चाहिए।'),
('Mercury','Jupiter','hi',
 'केन्द्र, त्रिकोण, उच्च, स्वक्षेत्र या 2, 11 भाव में होने पर शरीर सुख, धनलाभ, राजप्रीति, विवाह उत्सव, मधुर भोजन, गोधन लाभ, पुराण श्रवण, देव-गुरु भक्ति, दान-धर्म, यज्ञादि और शिव पूजा के अवसर मिलते हैं। दशेश से केन्द्र, त्रिकोण, लाभ, या बलवान होने पर भाई/पुत्रोत्पत्ति से उत्साह, धन संचय, पशु-यश वृद्धि और अन्नदान की सामर्थ्य होती है।',
 'नीच, अस्त, 6, 8, 12 भाव, शनि-मंगल दृष्ट/युक्त होने पर कलह, सरकारी टकराव, चोर से शरीर कष्ट, माता-पिता की हानि, मानहानि, राजदण्ड, विष/सर्प/ज्वर से पीड़ा और खेती बाड़ी की हानि होती है। दशेश से 6, 8, 12 में बलहीन होने पर शरीर कष्ट, अंगहीनता, स्त्री-भाइयों से विषमता, राजकोप, धनहानि, अचानक कलह और पक्षी/ब्राह्मण से भय होता है। 2, 7 भाव/भावेश होने पर देहबाधा (शरीर कष्ट) होती है।',
 'शिव सहस्रनाम या सहस्ररुद्रीयाभिषेक, तथा गाय, भूमि व सुवर्ण का दान करना चाहिए।'),
('Mercury','Saturn','hi',
 'स्वोच्च, स्वक्षेत्र, केन्द्र, त्रिकोण या लाभ में होने पर घर में कल्याण-कार्यों की वृद्धि, राज्य/अधिकार-प्राप्ति, मन में उमंग, पशुधन वृद्धि, अच्छे स्थान व तीर्थस्थानों पर रहने का सुयोग बनता है।',
 'लग्न या दशेश से 8, 12 भाव में होने पर शत्रुओं से अनेक कष्ट, स्त्री-पुत्रादि को पीड़ा, बुद्धि भ्रष्टता, बन्धुओं/सहयोगियों की हानि, कार्यहानि, मनोविकार, विदेश गमन और दुःस्वप्न देखने को मिलते हैं। 2, 7 भावेश होने पर अपमृत्यु होने का योग होता है।',
 'दोष शान्ति के लिए मृत्युंजयमन्त्र का जप और काली गाय या भैंस का दान करना चाहिए।'),
('Ketu','Ketu','hi',
 'केतु लग्नेश, 9, 10 भावेश या 4 भावेश के साथ हो तो धन-धान्य की वृद्धि, चौपाए जीव से लाभ, स्त्री-पुत्रों का सुख, राजा की प्रसन्नता, जायदाद वृद्धि/अधिकार-प्राप्ति और घर में गोधन की वृद्धि होती है।',
 'नीच/अस्तंगत ग्रह के साथ या 8, 12 भाव में हो तो हृदय रोग, मानहानि, धन-धान्य-पशु हानि, स्त्री-पुत्रादि को पीड़ा और मन में चंचलता व विकार होता है। 2, 7 भावेशों से सम्बन्ध या 2, 7 भाव में होने पर अस्वस्थता, कष्ट और अपने लोगों से वियोग होता है।',
 'शान्ति के लिए दुर्गा पाठ व मृत्युंजय जप करना चाहिए।'),
('Ketu','Venus','hi',
 'स्वोच्च, स्वक्षेत्र, केन्द्र, त्रिकोण, लाभ या दशमेश के साथ हो तो राजा की प्रसन्नता, सौभाग्य वृद्धि, वस्त्र उपभोग, धन-सुख-वाहन प्राप्ति, तीर्थ यात्रा (रामेश्वरम्) और ग्राम/भूमि/जायदाद का लाभ होता है। दशेश से केन्द्र, त्रिकोण या 3, 11 भाव में हो तो शरीर सुख, घर में वृद्धि, खान-पान व प्रतिष्ठित वाहनों की प्राप्ति होती है।',
 'दशेश से 6, 8, 12 में या पापयुक्त हो तो अचानक कलह और पशु-धान्य की कमी होती है। नीच ग्रह युक्त या लग्न से 6, 8 राशि में हो तो मनमुटाव, सिर-आँख में पीड़ा, हृदय रोग, मान-धन-पशु हानि और स्त्री-पुत्र को पीड़ा होती है। 2, 7 भावेश हो तो मनोविकार व शरीर कष्ट होता है।',
 'दुर्गा देवी का पाठ, और सफेद गाय या दुधारू भैंस का दान करना चाहिए।'),
('Ketu','Sun','hi',
 'उच्च, स्वक्षेत्र, केन्द्र, त्रिकोण, लाभ या शुभ दृष्ट हो तो धन-धान्य लाभ, राजा की कृपा से वैभव, शुभ कार्यों की पूर्णता, मनवांछित कार्यसिद्धि व सर्वत्र सुख होता है। दशेश से केन्द्र, कोण, लाभ या धन स्थान में हो तो शरीर सुख, धन लाभ, पुत्र-प्राप्ति, साहस, कार्य सफलता और ग्राम/बस्ती में प्रतिष्ठित स्थान मिलता है (अन्त में कुछ सुख भी मिलता है)।',
 '8, 12 राशि में या पापयुक्त हो तो राजभय, माता-पिता वियोग, विदेशगमन, चोर-सर्प-विष पीड़ा, विरोध, राजदण्ड से धनहानि, शोक, ज्वर और संताप होता है। दशेश से 8, 12 में या पापयुक्त हो तो अनाज की कमी, भय, पशु-धन हानि और प्रारम्भ-मध्य में क्लेश होता है। 2, 7 भावेश होने पर अपमृत्यु होती है।',
 'स्वर्णनिर्मित गाय की प्रतिमा अथवा सुवर्णयुक्त गाय का दान करना चाहिए।'),
('Ketu','Moon','hi',
 'पूर्ण, स्वक्षेत्र, उच्च, केन्द्र, त्रिकोण, लाभ, धनभाव या शुभयुक्त हो तो राज-सम्बन्ध, उत्साह, कल्याण, सुख, घर-भूमि लाभ, भोग सामग्री, व्यवसाय में लाभ, देवालय/तड़ाग निर्माण, पुण्य कार्य और स्त्री-पुत्र का सुख होता है। दशेश से केन्द्र, त्रिकोण, लाभ में या बली हो तो कृषि-पशु-भूमि लाभ, प्रियजनों से मिलन, कार्यसिद्धि, दूध-घी की बहुतायत, स्वास्थ्य लाभ, राजप्रीति और सम्मान मिलता है।',
 'क्षीण, नीच, 6, 8, 12 भाव में हो तो सुख में कमी, मनस्ताप, कार्य विघ्न, भय, माता-पिता वियोग, देह शिथिलता, व्यवसाय में कम लाभ और पशु नाश होता है। दशेश से 6, 8, 12 या बलहीन हो तो धन-धान्य हानि, व्याकुलता, बन्धु-वैर, और भाइयों को पीड़ा होती है (अन्त में राजभय व विदेश गमन भी होता है)। अष्टमेश या 2, 7 भावेश से युक्त हो तो अपमृत्यु का भय होता है।',
 'चन्द्रमा का दान-जप और देवी जप/पाठ आदि करना चाहिए।'),
('Ketu','Mars','hi',
 'स्वक्षेत्र, स्वोच्च, केन्द्र-त्रिकोण, शुभ युक्त/दृष्ट हो तो प्रारम्भ में शुभ फल, ग्राम/जायदाद लाभ, धन-पशु-खेत लाभ और राजा की कृपा से वैभव मिलता है। नवम भाव में दशमेश के साथ/सम्बन्ध हो तो भूमि लाभ व सुख होता है। दशेश से केन्द्र, त्रिकोण, 3, 11 भाव में हो तो राजप्रीति, यश और पुत्र-मित्र सुख होता है (मध्य में सुख व धन लाभ होता है)।',
 'दशेश से 8, 12 या द्वितीय में हो तो मृत्यु/अपमृत्यु भय, विदेश में मुसीबत, वृथा भ्रमण, प्रमेह/मूत्र रोग, राज-चोर भय, कलह और मानसिक क्लेश होता है। 2, 7 भावेश हो तो ताप ज्वर, विष संक्रमण, स्त्री कष्ट और अपमृत्यु भय होता है।',
 'शान्तिकार्य, हवन और बैल या बछड़े का दान करना चाहिए।'),
('Ketu','Rahu','hi',
 'शुभ उच्चादि राशि, मित्र गृह, स्वगृह, केन्द्र, त्रिकोण या 2, 3, 11 भाव में हो तो तुरन्त धन लाभ, ग्राम/भूमि अधिकार, पशु लाभ, भ्रमण, म्लेच्छ राजा के सहयोग से सुख और धन-धान्य वृद्धि होती है (बाद में सब शुभ होता है)।',
 '8, 12 में या पापदृष्ट/युक्त हो तो अधिक मूत्र त्याग, कमजोरी, सर्दी-बुखार, संक्रमण, छोटे उपद्रव (फोड़े-फुंसी), कलह, प्रमेह और शूल रोग होता है (प्रारम्भ में कष्ट भी होता है)। 2, 7 भाव में हो तो महान् भय व क्लेश होता है।',
 'शान्ति के लिए दुर्गापाठ कराना चाहिए।'),
('Ketu','Jupiter','hi',
 'केन्द्र, त्रिकोण, लाभ, स्वोच्च, स्वक्षेत्र, लग्नेश के साथ या 9, 10 भावेश से युक्त हो तो धन-धान्य-सम्पत्ति वृद्धि, राजप्रीति, उत्साह, वाहन लाभ, कल्याण कार्य, पुत्र लाभ, तीर्थ स्नान, विजय, और राजा/अधिकारी से भेंट होती है। दशेश से केन्द्र, त्रिकोण, 3, 11 या शुभयुक्त हो तो मित्रता, सुन्दर वस्त्र, दूरस्थान यात्रा, बन्धु पोषण और सांसारिक सुख मिलता है।',
 'लग्न या दशेश से 6, 8, 12 या नीचगत हो तो चोर-सर्प-चोट भय, धन-धान्य हानि, पुत्र-स्त्री वियोग, क्लेश और अन्त में बड़ा कष्ट होता है। दशेश से केन्द्रादि में होने पर भी आरम्भ में शरीर कष्ट व अन्त में स्थान परिवर्तन/कलह होती है। 2, 7 भावेश होने पर अपमृत्यु का भय होता है।',
 'शिव सहस्रनाम का पाठ व महामृत्युंजयमन्त्र का जप करना चाहिए।'),
('Ketu','Saturn','hi',
 '7, 9, 12, 4, 8 राशियों में, स्वक्षेत्र, केन्द्र, त्रिकोण, 3, 11 भाव, शुभ नवांश या शुभ दृष्ट/युक्त हो तो सब कार्य सिद्ध होते हैं, अधिकारी/राजा से सहयोग/भेंट, भ्रमण, ग्राम सुख और परिजनों को सुख मिलता है। (चौपाए धन का लाभ भी उल्लिखित है)।',
 '8, 12 भाव में या पाप फलप्रद हो तो पीड़ा, बन्धन, क्लेश, सन्ताप, सरकारी काम में धनहानि, भय, स्थान परिवर्तन/हानि, परदेश वास, चोर भय, आलस्य व उदासी होती है। दशेश से 6, 8, 12 में या पापयुक्त हो तो शारीरिक/मानसिक कष्ट, कार्य विघ्न, मानहानि और माता-पिता वियोग होता है। 2, 7 भावेश होने पर अपमृत्यु का भय होता है।',
 'काली गाय या भैंस का दान करें व काले तिलों से (घी मिलाकर) हवन करें।'),
('Ketu','Mercury','hi',
 'केन्द्र, त्रिकोण, लाभ, स्वोच्चादि गत हो तो राज्यलाभ (अधिकार/प्रतिष्ठा), सुख, शुभ समाचार, पुत्र प्राप्ति, सभाओं से धन लाभ, कम परिश्रम से धर्मार्जन, विवाह, घर में शुभ कार्य और वस्त्राभरण मिलते हैं। 9, 10 भावेश के साथ हो तो भाग्य वृद्धि, विद्वानों से समागम व उत्तम बौद्धिक कार्य होते हैं। दशेश से केन्द्र, त्रिकोण, लाभ में हो तो स्वास्थ्य, बड़ा लाभ, पुत्र की उन्नति व व्यवसाय में लाभ होता है।',
 '6, 8, 12 भाव में शनि-मंगल-राहु युक्त/दृष्ट हो तो राजकीय लोगों से विरोध, दूसरे के घर निवास, वाहन-पशु-धन नाश और अन्त में क्लेश व परिवार को पीड़ा होती है। दशेश से 6, 8, 12 या निर्बल हो तो आरम्भ में कष्ट-परिवार पीड़ा, राजभय और अन्त में अपमृत्यु होती है।',
 'विष्णुसहस्रनाम का जप करना चाहिए।'),
('Venus','Venus','hi',
 'लग्न से 1, 4, 5, 7, 9, 10, 11 भावों में या बली होने पर ब्राह्मणों के सहयोग से धन लाभ, पशुधन लाभ, पुत्रोत्सव, घर में कल्याण कार्य और राजसम्मान प्राप्त होता है। उच्च, स्वक्षेत्री या स्व/उच्च नवांश में होने पर नए घर का निर्माण, मधुर भोजन, स्त्री-पुत्र सुख, अन्नदान और बड़े लोगों की सहायता से भौतिक सुख मिलते हैं। लग्न से 3, 6, 10, 11 भाव में शुभ युक्त/दृष्ट होने पर राज्यलाभ, उत्साह, राजप्रीति और घर में खुशहाली बढ़ती है।',
 '6, 8, 12 भाव में या पापयुक्त/दृष्ट होने पर चोर-ठग से भय, घाव का भय, सर्वत्र कष्ट, राजस्थान पर लोगों से द्वेष, इष्ट लोगों का वियोग और स्त्री-पुत्रादि को पीड़ा होती है।',
 'यदि शुक्र 2 या 7 भावेश हो तो मृत्यु तुल्य कष्ट के निवारणार्थ दुर्गापाठ एवं गोदान (धेनुदान) कराना चाहिए।'),
('Venus','Sun','hi',
 'उच्च, स्वक्षेत्र, मित्र राशि, केन्द्र त्रिकोण या दशेश से 2, 11 भाव में होने पर धन-राज्य लाभ, स्त्री प्राप्ति, इष्टमित्रों से समागम, माता-पिता का सुख और भाई से लाभ या सुख-सौभाग्य प्राप्त होता है।',
 'उच्च या नीच में न होने पर मानसिक क्षोभ, राजकीय पुरुषों से विरोध और दायाद (उत्तराधिकारियों) से कलह होती है। 8, 12 भाव, शत्रुक्षेत्री, नीच या पापवर्ग में होने पर शरीर-मन में कष्ट, कठोर भाषण, पिता को कष्ट, चोर-सर्प भय, अनेक रोग और घर/सम्पत्ति का विनाश होता है।',
 'सप्तमेश होने पर बाधाओं के शमन हेतु सूर्यदान और सूर्य का जप-पाठ कराना चाहिए।'),
('Venus','Moon','hi',
 'केन्द्र, त्रिकोण, लाभ, उच्च, स्वक्षेत्र, पूर्ण बिम्ब या शुभ युक्त/दृष्ट होने पर वाहन लाभ, घर में अधिक सुख, बड़े लोगों के सहयोग से ऐश्वर्य, गंगादि नदी में स्नान, देव-ब्राह्मण पूजा, आमोद-प्रमोद और व्यवसाय में लाभ होता है। दशेश से केन्द्र, त्रिकोण, 3, 11 में होने पर राजकृपा, देश-ग्राम का अधिकार, यश, कूप-बाग (सार्वजनिक सुविधाओं) का निर्माण, धनसंग्रह और प्रारम्भ में शरीर सुख मिलता है।',
 'नीच, अस्त, या 6, 8, 12 भाव (लग्न या दशेश से) में होने पर तत्काल धन नाश, महान् भय, शरीर-मन कष्ट, मुक़दमेबाज़ी, विदेश गमन, स्त्री-पुत्र को पीड़ा और अपनों का वियोग होता है। अन्तर्दशा के अन्त में क्लेश होता है।',
 '(मूल पाठ में इस खण्ड के लिए कोई विशिष्ट उपाय उल्लिखित नहीं है)।'),
('Venus','Mars','hi',
 'केन्द्र, त्रिकोण, स्वोच्च, स्वराशि, लाभगत या 1, 9, 10 भावेश से युक्त होने पर राजयोग, सम्पत्ति वृद्धि, वस्त्राभूषणों की प्राप्ति और इष्ट सिद्धि होती है।',
 'लग्न या दशापति से 8, 12 भाव में होने पर शीत ज्वर पीड़ा, माता-पिता को कष्ट, मनोविकार के कारण स्थान हानि, अपनों की हानि, सरकारी आदमियों से विरोध, धन का अधिक व्यय और ग्राम-भूमि की हानि होती है।',
 '2, 7 भावेश होने पर शरीर कष्ट निवारण के लिए मंगल दान, पूजन, भैरव/हनुमान् पूजन तथा वृषदान करना चाहिए।'),
('Venus','Rahu','hi',
 'केन्द्र, त्रिकोण, लाभ, उच्च, शुभ दृष्ट या योगकारक युक्त होने पर बहुत सुख, धन-धान्य लाभ, इष्ट मित्रों का समागम, यात्रा में सफलता व पशुधन/अचल सम्पत्ति की वृद्धि होती है। लग्न से उपचय (3, 6, 10, 11) में होने पर प्रारम्भ के 5 महीनों में शत्रु नाश, उत्साह व राजप्रीति होती है। नैऋत्य दिशा की यात्रा, बड़े लोगों से सम्मान, ब्राह्मणों का उपकार और तीर्थ यात्राओं का फल प्राप्त होता है।',
 'अन्तर्दशा के अन्त में ज्वर, अपच, अम्लपित्त (पित्त), कार्यों में विघ्न और यात्रा में मानसिक कष्ट होते हैं। दशेश से 8, 12 में या पापयुक्त होने पर अशुभ कार्यों में लिप्तता, माता-पिता को कष्ट और सर्वत्र लोगों से द्वेष होता है। 2, 7 भाव में होने पर देह में शिथिलता होती है।',
 'देह शिथिलता के परिहार के लिए मृत्युंजय मन्त्र का जप करना चाहिए।'),
('Venus','Jupiter','hi',
 'उच्च, स्वराशि, केन्द्र, दशेश से शुभ भाव या 5, 9 भाव में होने पर नष्ट राज्य-धन की प्राप्ति, मित्र राजा का सहयोग, राजसम्मान, सवारी प्राप्ति, विद्वानों से समागम, शास्त्रों में परिश्रम, पुत्रोत्सव और माता-पिता का सुख होता है।',
 'दशेश से 6, 12 भाव या पापयुक्त होने पर राजा-चोर से पीड़ा, शरीर कष्ट, बन्धुओं को कष्ट, कलह से मनोव्यथा, स्थान परिवर्तन, प्रवास और नाना प्रकार के रोग होते हैं।',
 '2, 7 भावेश होने पर शरीर कष्ट निवारण के लिए महामृत्युंजय मन्त्र का जप करना चाहिए।'),
('Venus','Saturn','hi',
 'उच्च, परमोच्च, स्वराशि, केन्द्र, त्रिकोण या स्व/उच्च नवांश में होने पर बहुत सुख, इष्ट जनों से समागम, राजद्वार पर सम्मान, पुत्री का जन्म और पुण्यतीर्थों की यात्रा होती है।',
 'नीचगत होने पर अनेक क्लेश, शरीर में आलस्य और आय से अधिक व्यय होता है। लग्न या दशेश से 8, 12 भावगत या नीचादिगत होने पर प्रारम्भ में माता-पिता समेत सबको कष्ट, परदेश भ्रमण, व्यवसाय में अवनति और दुधारू पशुओं की हानि होती है।',
 '2, 7 भावेश होने पर दोष निराकरण के लिए तिल का हवन, मृत्युंजय जप एवं चण्डीपाठ करना चाहिए।'),
('Venus','Mercury','hi',
 'लग्न से केन्द्र, त्रिकोण, 11, उच्च या स्वराशि में होने पर राजा की विशेष अनुकूलता, सौभाग्य, पुत्रप्राप्ति, सन्मार्ग से धनागम, पुराण श्रवण, श्रृंगारप्रिय लोगों का साथ और नित्य मधुर भोजन प्राप्त होता है।',
 'दशेश से 6, 8, 12 में, बलहीन या पापदृष्ट/युक्त होने पर चौपाए धन की हानि, दूसरों के घर निवास, मन में विकलता और व्यापार में सर्वत्र हानि होती है। दशान्त में बहुत कष्ट तथा शीत-वायु का बुखार होता है।',
 'सप्तमेश होने पर शरीर कष्ट निवारणार्थ विष्णु सहस्रनाम का जप करना चाहिए।'),
('Venus','Ketu','hi',
 'उच्च, स्वक्षेत्री, योगकारक से युक्त/सम्बन्धित, केन्द्र-त्रिकोण या उपचय भावों में होने पर प्रारम्भ में बहुत शुभफल, गाय-भैंस लाभ, उत्तम भोजन, व्यवसाय लाभ, धन-धान्य वृद्धि और युद्ध में विजय होती है। अन्तर्दशा के अन्त में सुख अधिक होता है।',
 'मध्य में बीच-बीच में कष्ट होता रहता है। दशेश से 8, 12 में पापयुक्त होने पर चोर-चोट भय, बुद्धि हानि, सिर रोग, अकारण कलह, प्रमेह रोग, धनव्यय, स्त्री-पुत्र विरोध और कार्य-यात्रा में हानि होती है।',
 '2, 7 भावेश से सम्बन्ध होने पर मृत्युंजय जप, मेषदान (बकरे का दान) तथा शुक्र की शान्ति (दुर्गापाठ आदि) करनी चाहिए।')
